parameters.functionCode:
const now = new Date();
const invoices = items[0].json.invoices || items[0].json.data || items[0].json;

if (!Array.isArray(invoices)) {
  return [{ json: { error: 'No invoices array found in response', raw: items[0].json } }];
}

const categorized = invoices.map(inv => {
  const dueDate = new Date(inv.due_date || inv.dueDate);
  const daysPastDue = Math.floor((now - dueDate) / (1000 * 60 * 60 * 24));
  const invoiceAmount = parseFloat(inv.amount || inv.total || inv.amount_due || 0);

  let reminderTier;
  let reminderAction;

  if (daysPastDue < 0) {
    if (daysPastDue >= -3) {
      reminderTier = 'upcoming';
      reminderAction = 'Send courtesy reminder that payment is due soon';
    } else {
      reminderTier = 'not_due';
      reminderAction = 'No action needed';
    }
  } else if (daysPastDue === 0) {
    reminderTier = 'due_today';
    reminderAction = 'Send day-of payment reminder';
  } else if (daysPastDue <= 7) {
    reminderTier = 'gentle';
    reminderAction = 'Send friendly follow-up (1-7 days overdue)';
  } else if (daysPastDue <= 21) {
    reminderTier = 'firm';
    reminderAction = 'Send firm reminder with urgency (8-21 days overdue)';
  } else if (daysPastDue <= 45) {
    reminderTier = 'final';
    reminderAction = 'Send final notice before escalation (22-45 days overdue)';
  } else {
    reminderTier = 'escalate';
    reminderAction = 'Escalate to management / collections process (45+ days overdue)';
  }

  // Check if we already sent a reminder at this tier to prevent duplicate sends
  const lastReminderTier = inv.metadata?.lastReminderTier || inv.custom_fields?.last_reminder_tier || null;
  const shouldSend = reminderTier !== lastReminderTier && reminderTier !== 'not_due';

  return {
    invoiceId: inv.id || inv.invoice_id || inv.number,
    invoiceNumber: inv.number || inv.invoice_number || inv.id,
    clientName: inv.client_name || inv.customer_name || inv.contact?.name || 'Client',
    clientEmail: inv.client_email || inv.customer_email || inv.contact?.email || '',
    amount: invoiceAmount,
    amountFormatted: `$${invoiceAmount.toFixed(2)}`,
    currency: inv.currency || 'USD',
    dueDate: (inv.due_date || inv.dueDate || '').split('T')[0],
    daysPastDue: daysPastDue,
    reminderTier: reminderTier,
    reminderAction: reminderAction,
    shouldSend: shouldSend,
    lastReminderTier: lastReminderTier,
    invoiceUrl: inv.permalink || inv.invoice_url || inv.hosted_url || `https://yourinvoicetool.com/invoices/${inv.id}`,
    processedAt: now.toISOString()
  };
});

// Only return invoices that need action
const actionable = categorized.filter(inv => inv.shouldSend);

if (actionable.length === 0) {
  return [{ json: { noAction: true, totalChecked: invoices.length, message: 'No invoices require follow-up at this time.' } }];
}

return actionable.map(inv => ({ json: inv }));

